import{_ as a,o as e,c as r,a7 as s}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Combat System","description":"","frontmatter":{},"headers":[],"relativePath":"en/modes/combat.md","filePath":"en/modes/combat.md","lastUpdated":1775394001000}'),i={name:"en/modes/combat.md"};function o(d,t,n,l,c,h){return e(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="combat-system" tabindex="-1">Combat System <a class="header-anchor" href="#combat-system" aria-label="Permalink to &quot;Combat System&quot;">​</a></h1><p>Morimens uses a <strong>turn-based card combat system</strong>. Each turn, you draw cards, spend Arithmetica to play them, and build toward powerful Madness Burst and Key Order activations.</p><h2 id="turn-structure" tabindex="-1">Turn Structure <a class="header-anchor" href="#turn-structure" aria-label="Permalink to &quot;Turn Structure&quot;">​</a></h2><p>Each turn follows this flow:</p><ol><li><strong>Draw Phase</strong> -- Draw cards into your hand.</li><li><strong>Play Phase</strong> -- Spend Arithmetica to play cards from your hand.</li><li><strong>Resolution Phase</strong> -- Card effects resolve; Madness Points and Silver Key update.</li><li><strong>Enemy Phase</strong> -- Enemies take their actions.</li></ol><h2 id="arithmetica-算力" tabindex="-1">Arithmetica (算力) <a class="header-anchor" href="#arithmetica-算力" aria-label="Permalink to &quot;Arithmetica (算力)&quot;">​</a></h2><p><span class="arithmetica-cost">Arithmetica</span> is the energy used to play cards.</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Value</th></tr></thead><tbody><tr><td>Per-turn Arithmetica</td><td><strong>5</strong></td></tr><tr><td>Carry over</td><td>No (unused Arithmetica is lost at end of turn)</td></tr></tbody></table><ul><li>Each card has an Arithmetica cost displayed on it.</li><li>You must manage your 5 Arithmetica budget each turn to play the optimal combination of cards.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Not every card needs to be played every turn. Sometimes holding a card for a better turn or saving Arithmetica for a combo is the correct play.</p></div><h2 id="madness-points-狂气" tabindex="-1">Madness Points (狂气) <a class="header-anchor" href="#madness-points-狂气" aria-label="Permalink to &quot;Madness Points (狂气)&quot;">​</a></h2><p>Madness Points build during combat and trigger a free ability at 100.</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Value</th></tr></thead><tbody><tr><td>Trigger Threshold</td><td><strong>100 Madness Points</strong></td></tr><tr><td>Cost to Trigger</td><td><strong>Free</strong> (no Arithmetica cost)</td></tr><tr><td>After Trigger</td><td>Resets to 0 and begins building again</td></tr></tbody></table><p>Madness Points accumulate through:</p><ul><li>Taking damage</li><li>Playing certain cards</li><li>Realm-specific effects</li></ul><p>When Madness Points reach 100, the active Awakener&#39;s <strong>Madness Burst</strong> triggers automatically at no cost.</p><h2 id="silver-key" tabindex="-1">Silver Key <a class="header-anchor" href="#silver-key" aria-label="Permalink to &quot;Silver Key&quot;">​</a></h2><p>Silver Key energy builds during battle toward a powerful Key Order activation.</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Value</th></tr></thead><tbody><tr><td>Activation Threshold</td><td><strong>1000 Silver Key</strong></td></tr><tr><td>Trigger</td><td>Manual activation</td></tr><tr><td>After Trigger</td><td>Resets to 0</td></tr></tbody></table><p>Silver Key accumulates through card play and combat actions. <span class="realm-badge realm-chaos">Chaos</span> realm effects accelerate Silver Key generation.</p><p>See <a href="./../key-orders/">Key Orders</a> for details on available Key Order abilities.</p><h2 id="card-types-in-combat" tabindex="-1">Card Types in Combat <a class="header-anchor" href="#card-types-in-combat" aria-label="Permalink to &quot;Card Types in Combat&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Card Type</th><th>Description</th><th>Cost</th></tr></thead><tbody><tr><td><span class="card-type-badge card-command">Command Card</span></td><td>Core Awakener abilities (4 per character)</td><td>Varies (Arithmetica)</td></tr><tr><td><span class="card-type-badge card-spirit">Spirit Awakening Card</span></td><td>Powerful signature ability (1 per character)</td><td>High Arithmetica cost</td></tr><tr><td><span class="card-type-badge card-madness">Madness Burst</span></td><td>Automatic trigger at 100 Madness Points</td><td><strong>Free</strong></td></tr></tbody></table><h2 id="team-in-combat" tabindex="-1">Team in Combat <a class="header-anchor" href="#team-in-combat" aria-label="Permalink to &quot;Team in Combat&quot;">​</a></h2><ul><li>Up to <strong>4 Awakeners</strong> participate in combat.</li><li>Each Awakener contributes their cards to the shared deck.</li><li>The active Awakener receives Madness Points and can trigger Madness Burst.</li></ul><h2 id="combat-tips" tabindex="-1">Combat Tips <a class="header-anchor" href="#combat-tips" aria-label="Permalink to &quot;Combat Tips&quot;">​</a></h2><ol><li><strong>Plan your Arithmetica</strong> -- With 5 per turn, prioritize high-impact cards.</li><li><strong>Track Madness Points</strong> -- Know when Madness Burst will trigger to time it with your strategy.</li><li><strong>Build Silver Key</strong> -- In longer fights, reaching 1000 Silver Key for a Key Order can be the deciding factor.</li><li><strong>Match realms</strong> -- Realm synergy bonuses apply in combat. See <a href="./../realms/">Realms</a>.</li><li><strong>Upgrade cards</strong> -- Higher card levels dramatically increase combat effectiveness. See <a href="./../cards/upgrade.html">Card Upgrades</a>.</li></ol><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./../cards/">Card System</a></li><li><a href="./../realms/">Realms Overview</a></li><li><a href="./../key-orders/">Key Orders</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li></ul>',29)])])}const p=a(i,[["render",o]]);export{u as __pageData,p as default};
